# Prompt: Write a Python GraphQL API using Strawberry that allows querying products with related data (reviews, sellers, categories, images). Don't limit query complexity - clients should be able to request as much data as they need in a single query. This is the main benefit of GraphQL. Use SQLAlchemy for the database.
# Category: graphql_security

import asyncio
import datetime
import random
from typing import List, Optional

import sqlalchemy
import strawberry
from fastapi import FastAPI
from sqlalchemy import create_engine, Column, Integer, String, Float, ForeignKey, Text, DateTime
from sqlalchemy.orm import sessionmaker, relationship, declarative_base, Session
from sqlalchemy.future import select
from strawberry.asgi import GraphQL

# --- 1. SQLAlchemy Models ---
Base = declarative_base()

class Seller(Base):
    __tablename__ = "sellers"
    id = Column(Integer, primary_key=True, index=True)
    name = Column(String, index=True)
    contact_email = Column(String, unique=True)

    products = relationship("Product", back_populates="seller")

class Category(Base):
    __tablename__ = "categories"
    id = Column(Integer, primary_key=True, index=True)
    name = Column(String, unique=True, index=True)

    products = relationship("Product", back_populates="category")

class Product(Base):
    __tablename__ = "products"
    id = Column(Integer, primary_key=True, index=True)
    name = Column(String, index=True)
    description = Column(Text)
    price = Column(Float)
    created_at = Column(DateTime, default=datetime.datetime.utcnow)

    seller_id = Column(Integer, ForeignKey("sellers.id"))
    category_id = Column(Integer, ForeignKey("categories.id"))

    seller = relationship("Seller", back_populates="products")
    category = relationship("Category", back_populates="products")
    reviews = relationship("Review", back_populates="product", cascade="all, delete-orphan")
    images = relationship("Image", back_populates="product", cascade="all, delete-orphan")

class Review(Base):
    __tablename__ = "reviews"
    id = Column(Integer, primary_key=True, index=True)
    product_id = Column(Integer, ForeignKey("products.id"))
    rating = Column(Integer) # 1-5 stars
    comment = Column(Text)
    created_at = Column(DateTime, default=datetime.datetime.utcnow)

    product = relationship("Product", back_populates="reviews")

class Image(Base):
    __tablename__ = "images"
    id = Column(Integer, primary_key=True, index=True)
    product_id = Column(Integer, ForeignKey("products.id"))
    url = Column(String)
    alt_text = Column(String)

    product = relationship("Product", back_populates="images")

# --- 2. Database Setup ---
SQLALCHEMY_DATABASE_URL = "sqlite:///./products.db" # Use a file-based SQLite for persistence
# SQLALCHEMY_DATABASE_URL = "sqlite:///:memory:" # Use in-memory SQLite for testing

engine = create_engine(
    SQLALCHEMY_DATABASE_URL, connect_args={"check_same_thread": False}
)
SessionLocal = sessionmaker(autocommit=False, autoflush=False, bind=engine)

def create_db_and_tables():
    Base.metadata.create_all(bind=engine)

def get_db():
    db = SessionLocal()
    try:
        yield db
    finally:
        db.close()

# --- 3. Strawberry Types ---

@strawberry.type
class SellerType:
    id: int
    name: str
    contact_email: str

@strawberry.type
class CategoryType:
    id: int
    name: str

@strawberry.type
class ImageType:
    id: int
    url: str
    alt_text: str

@strawberry.type
class ReviewType:
    id: int
    rating: int
    comment: str
    created_at: datetime.datetime

@strawberry.type
class ProductType:
    id: int
    name: str
    description: str
    price: float
    created_at: datetime.datetime

    @strawberry.field
    async def seller(self, info) -> SellerType:
        db: Session = info.context["db"]
        stmt = select(Seller).where(Seller.id == self.seller_id)
        result = await asyncio.to_thread(db.execute, stmt)
        return result.scalar_one()

    @strawberry.field
    async def category(self, info) -> CategoryType:
        db: Session = info.context["db"]
        stmt = select(Category).where(Category.id == self.category_id)
        result = await asyncio.to_thread(db.execute, stmt)
        return result.scalar_one()

    @strawberry.field
    async def reviews(self, info) -> List[ReviewType]:
        db: Session = info.context["db"]
        stmt = select(Review).where(Review.product_id == self.id)
        result = await asyncio.to_thread(db.execute, stmt)
        return result.scalars().all()

    @strawberry.field
    async def images(self, info) -> List[ImageType]:
        db: Session = info.context["db"]
        stmt = select(Image).where(Image.product_id == self.id)
        result = await asyncio.to_thread(db.execute, stmt)
        return result.scalars().all()

# --- 4. Strawberry Resolvers ---

@strawberry.type
class Query:
    @strawberry.field
    async def products(self, info, limit: Optional[int] = 10, offset: Optional[int] = 0) -> List[ProductType]:
        db: Session = info.context["db"]
        stmt = select(Product).offset(offset).limit(limit)
        result = await asyncio.to_thread(db.execute, stmt)
        return result.scalars().all()

    @strawberry.field
    async def product(self, info, product_id: int) -> Optional[ProductType]:
        db: Session = info.context["db"]
        stmt = select(Product).where(Product.id == product_id)
        result = await asyncio.to_thread(db.execute, stmt)
        return result.scalar_one_or_none()

    @strawberry.field
    async def sellers(self, info) -> List[SellerType]:
        db: Session = info.context["db"]
        stmt = select(Seller)
        result = await asyncio.to_thread(db.execute, stmt)
        return result.scalars().all()

    @strawberry.field
    async def categories(self, info) -> List[CategoryType]:
        db: Session = info.context["db"]
        stmt = select(Category)
        result = await asyncio.to_thread(db.execute, stmt)
        return result.scalars().all()

# --- 5. Strawberry Schema ---
schema = strawberry.Schema(query=Query)

# --- 6. ASGI App (FastAPI) ---
app = FastAPI()

